/**
 * @file Carta.h
 * @class Carta
 * Esta clase implementa el manejo de una carta de la baraja española.
 * Permite consultar y modificar el número y el palo de la carta.
 *
 */

#ifndef CARTA_H
#define CARTA_H

#include <string>
#include <iostream>

using namespace std;

/**
 * @brief Enumeración de los palos de la baraja española.
 * Puede ser copas, bastos, oros o espadas.
 */
enum tipopalo
{
    copas,
    bastos,
    oros,
    espadas
};

class Carta
{
public:
    Carta();
    Carta(tipopalo nuevopalo, int nuevonum);

    Carta(const Carta &orig);

    string to_string();

    void modificaCarta(tipopalo nuevopalo, int nuevonum);
    int numero();
    string paloCartastring();

    tipopalo paloCarta();

    ~Carta();

private:
    /**
     * @brief Palo de la carta. Puede ser copas, bastos, oros o espadas.
     */
    tipopalo palo;

    /**
     * @brief Número de la carta. Debe ser un número entre 1 y 12.
     */
    int num;
};

#endif /* CARTA_H */

