/**
 * @file Mano.cpp
 * @class Mano
 */

/**
 * @brief Constructor por defecto de la clase Mano. Inicializa el número de cartas a 0.
 */
Mano::Mano()
{
}

/**
 * @brief Constructor de copia de la clase Mano. Crea una nueva mano con las mismas cartas que la mano original.
 * @param orig La mano original de la cual se copiarán las cartas.
 */
Mano::Mano(const Mano &orig)
{
}

/**
 * @brief Destructor de la clase Mano.
 */
Mano::~Mano()
{
}

/**
 * @brief Añade una nueva carta a la mano.
 * @param nuevacarta La carta que se añadirá a la mano.
 * @pre El número de cartas en la mano no debe superar el valor de MAX (10). Si se intenta añadir una carta cuando la mano ya tiene 10 cartas, no se añadirá la carta y se mantendrá la mano sin cambios.
 */
void Mano::anaideCarta(Carta &nuevacarta)
{
    cartas[numCartas] = nuevacarta;
    numCartas++;
}

/**
 * @brief Descarta una carta de la mano en la posición especificada.
 * @param pos La posición de la carta que se desea descartar.
 * @pre La posición debe ser un valor válido entre 0 y numCartas-1.
 */
void Mano::descartaCarta(int pos)
{
    for (int i = pos; i < numCartas; i++)
    {
        cartas[i] = cartas[i + 1];
    }
    numCartas--;
}

/**
 * @brief Cambia una carta de la mano en la posición especificada por una nueva carta.
 * @param nuevacarta La nueva carta que se desea colocar en la mano.
 * @param pos La posición de la carta que se desea cambiar.
 * @pre La posición debe ser un valor válido entre 0 y numCartas-1.
 */
void Mano::cambiaCarta(Carta &nuevacarta, int pos)
{
    cartas[pos] = nuevacarta;
}

/**
 * @brief Devuelve un string de la mano, indicando las cartas que contiene.
 * @return Una cadena que representa la mano, con cada carta separada por una coma
 */
string Mano::to_string()
{
    string cadcartas = "";
    for (int i = 0; i < numCartas; i++)
    {
        cadcartas = cadcartas + std::to_string(cartas[i].numero()) + " de " +
                    cartas[i].paloCartastring() + "\n";
    }
    return cadcartas;
}

/**
 * @brief Devuelve el número de cartas en la mano.
 * @return El número de cartas en la mano.
 */
int Mano::numeroCartas()
{
    return numCartas;
}

Carta &Mano::carta(int i)
{
    return cartas[i];
}

int cartasComunes(Mano &mano1, Mano &mano2)
{
    int numrepetidas = 0;
    for (int i = 0; i < mano1.numeroCartas(); i++)
    {
        for (int j = 0; j < mano2.numeroCartas(); j++)
        {
            if (mano1.carta(i).numero() == mano2.carta(j).numero() &&
                mano1.carta(i).paloCarta() == mano2.carta(j).paloCarta())
            {
                numrepetidas++;
            }
        }
    }
    return numrepetidas;
}

