 * @class Carta
 */

#include "Carta.h"
#include <string>
#include <iostream>

using namespace std;

/**
 * @brief Constructor por defecto de la clase Carta. Inicializa el número a 1 y el palo a copas.
 */
Carta::Carta()
{
}

/**
 * @brief Constructor de la clase Carta. Inicializa el número y el palo con los valores proporcionados.
 * @param nuevopalo El palo de la carta.
 * @param nuevonum El número de la carta.
 * @pre El número debe ser un valor entre 1 y 12
 * @pre El palo debe ser un valor válido de la enumeración tipopalo (copas, bastos, oros o espadas).
 */
Carta::Carta(tipopalo nuevopalo, int nuevonum)
{
    num = nuevonum;
    palo = nuevopalo;
}

/**
 * @brief Constructor de copia de la clase Carta. Crea una nueva carta con los mismos valores que la carta original.
 * @param orig La carta original de la cual se copiarán los valores.
 *
 */
Carta::Carta(const Carta &orig)
{
    num = orig.num;
    palo = orig.palo;
}

/**
 * @brief Devuelve un string de la carta, indicando su número y palo.
 * @return Una cadena que representa la carta en el formato "número de palo".
 */

string Carta::to_string()
{
    string palocarta;
    palocarta = std::to_string(num) + " de " + paloCartastring();
    return palocarta;
}

/**
 * @brief Modifica el número y el palo de la carta con los valores proporcionados.
 * @param nuevopalo El nuevo palo de la carta.
 * @param nuevonum El nuevo número de la carta.
 * @pre El número debe ser un valor entre 1 y 12
 * @pre El palo debe ser un valor válido de la enumeración tipopalo (copas, bastos, oros o espadas).
 */
void Carta::modificaCarta(tipopalo nuevopalo, int nuevonum)
{
    palo = nuevopalo;
    num = nuevonum;
}

/**
 * @brief Devuelve el número de la carta.
 * @return El número de la carta.
 */
int Carta::numero()
{
    return num;
}

/**
 * @brief Devuelve el palo de la carta como un string.
 * @return El palo de la carta en formato string (bastos, espadas, oros o copas).
 */
string Carta::paloCartastring()
{
    string palocarta;
    if (palo == bastos)
        palocarta = "bastos";
    if (palo == espadas)
        palocarta = "espadas";
    if (palo == oros)
        palocarta = "oros";
    if (palo == copas)
        palocarta = "copas";
    return palocarta;
}

/**
 * @brief Devuelve el palo de la carta como un valor de la enumeración tipopalo.
 * @return El palo de la carta en formato tipopalo (copas, bastos, oros o espadas).
 */
tipopalo Carta::paloCarta()
{
    return palo;
}

/**
 * @brief Destructor de la clase Carta.
 *
 */
Carta::~Carta()
{
}

