    Carta una(palo, 3);
    cout << una.to_string() << endl;
    palo = oros;
    una.modificaCarta(palo, 1);
    cout << una.to_string() << endl;
    cout << una.numero() << " de " << una.paloCartastring() << endl;
    cout << endl
